class ApiHandler implements SourceHandler
{
    protected ?int $count = null;

    public function read(IngestConfig $config, mixed $payload = null): Generator
    {
        $url = $config->sourceOptions['url'] ?? null;
        $headers = $config->sourceOptions['headers'] ?? [];

        if (!$url) {
            throw new SourceException("API URL is required in source options");
        }

        $response = Http::withHeaders($headers)->get($url);

        if (!$response->successful()) {
            throw new SourceException("API request failed: " . $response->status());
        }

        $data = $response->json('data') ?? $response->json();

        if (!is_array($data)) {
            throw new SourceException("API response must contain an array");
        }

        $this->count = count($data);

        foreach ($data as $item) {
            yield $item;
        }
    }

    public function getTotalRows(): ?int
    {
        return $this->count;
    }

    public function getProcessedFilePath(): ?string
    {
        return null;
    }

    public function cleanup(): void
    {
        // Nothing to clean up
    }
}

const retry = async () => {
    const { data } = await axios.post(`/api/v1/ingest/${run.value.id}/retry`);
    // The API returns a NEW run ID. Reset progress and start polling the new ID.
    run.value = data.data;
    progress.value = 0;
    startPolling(run.value.id);
};

const validateFile = (file) => {
    const errors = [];

    // File size validation (10MB max)
    const maxSize = 10 * 1024 * 1024;
    if (file.size > maxSize) {
        errors.push(`File size (${(file.size / 1024 / 1024).toFixed(2)}MB) exceeds maximum allowed size (10MB)`);
    }

    // File type validation
    const allowedTypes = [
        'text/csv',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
        'application/vnd.ms-excel'
    ];
    const allowedExtensions = ['.csv', '.xlsx', '.xls'];

    const hasValidType = allowedTypes.includes(file.type);
    const hasValidExtension = allowedExtensions.some(ext => 
        file.name.toLowerCase().endsWith(ext)
    );

    if (!hasValidType && !hasValidExtension) {
        errors.push('Invalid file type. Please upload a CSV or Excel file.');
    }

    return errors;
};

// Usage in upload function
const upload = async () => {
